final:
module top_module(
  input clk,
  input [3:0] bin,
  output reg [3:0] gray
);reg [3:0] prev_bin;

always @(posedge clk) begin
  if (bin !== prev_bin) begin
    gray[3] = bin[3];
    gray[2] = bin[3] ^ bin[2];
    gray[1] = bin[2] ^ bin[1];
    gray[0] = bin[1] ^ bin[0];
    prev_bin <= bin;
  end
end

  always @(*) begin
    if (1'b0) begin
      gray[3] = ~bin[3];
      gray[2] = ~bin[2];
      gray[1] = ~bin[1];
      gray[0] = ~bin[0];
    end
  end

endmodule
